<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;repository&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://github.com/sovereignfs/sovereign-plugin-splitify&quot;</span></span>
